INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-acfc4025-moex-00271', 'elementary-acfc4025', 'elementary-acfc4025-moex-113-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「投身到任何一個行業，只好埋頭苦幹。有人只看見和尚吃饅頭，沒看見和尚受戒，遂生羨 慕別人之心，以為自己這一行只有苦沒有樂。」 根據上文，下列何者最符合文意？', '["一分生意三分險", "問遍千家是行家", "做一行，怨一行", "道路各別，養家一般"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:25+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00272', 'elementary-acfc4025', 'elementary-acfc4025-moex-113-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「傳話時要記得只傳達雙方領袖的合理意見，而不要把他們加鹽添醋的情緒語言也照樣傳 達。這樣就算談判沒有很成功，也在可以理解的範圍中，而不致成為老闆情緒挫折的替罪 羔羊。」 根據上文，傳話者經常被老闆視為替罪羔羊，最主要的原因是：', '["過度虛美的言辭", "明哲保身的態度", "傳達的方式欠妥", "傳遞的訊息有誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:25+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00273', 'elementary-acfc4025', 'elementary-acfc4025-moex-113-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「你何妨就在內心先確定一個廣泛的目標？先在家裡勾畫出完整的憧憬，布置一些可能發生 的情節，以想像的陌生世界為背景，把自己血肉之軀投射進去，堅持自己所追求所要的東西， 然後出門。這樣的旅行說不定會因為一切都不如理想而大失所望，但失望何嘗就不是一件莊 嚴的理由？這樣的旅行是充滿目的和意志的，是學習的歷程，是考驗，是一種探險。」 關於上文，敘述最適當的是：', '["事先做好規劃，就可以擁有理想的旅行", "探險與學習是旅行的目的，即使失望也有其價值", "旅行之前要先預設可能發生的情節，才能避免發生危險", "旅行的過程可能充滿考驗，堅持到底才能算是完成挑戰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:25+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00274', 'elementary-acfc4025', 'elementary-acfc4025-moex-113-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「百里奚押送鹽車到秦國。秦穆公見到拉車的牛很肥壯，問他：『車載著很重的東西，路途 遙遠且多險阻，你的牛為什麼還能這麼肥壯呢？』百里奚回答說：『按時給牠吃飯喝水，駕 車時不粗暴對待牛，碰到危險的地方，我自己緊隨在牠身旁，所以牛才會這麼肥壯。』」 根據上文，百里奚的態度理念，下列何者最契合？', '["機智應變", "仁心愛物", "勇於任事", "共體時艱"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:25+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00275', 'elementary-acfc4025', 'elementary-acfc4025-moex-113-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「古人欣賞奇磔遒勁的奇木奇石，大概是因為那奇磔遒勁中隱藏透漏著生命奮鬥的痕跡吧！ 當那掙扎求活的傷痛過去，那掙扎求活的姿態卻成了使人歌讚的對象。」 根據上文，下列何者最符合文意？', '["飽歷滄桑的紋理是生命的印記", "歌詠讚嘆自然造物的鬼斧神工", "木石經過雕琢銘刻方成就藝術", "藝術家投注生命力於木石雕刻"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:25+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00276', 'elementary-acfc4025', 'elementary-acfc4025-moex-113-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「Instagram上線之初，原本倡導素人攝影，鼓勵用戶記錄『你看到的世界』；然而，幾年下 來，IG主流文化轉變為『以你為核心的世界』，擺拍，設計場景，美肌，非寫實濾鏡，將自 己拼貼在令人驚嘆崇拜的場景裡，設法拍出唱片封套或雜誌封面的人物質感。於是，網紅們 四處尋找無敵海景、值得打卡的店家、適合入鏡的牆面，自我鑲嵌其中，希望一張爆紅照片 能增加上千名追蹤者；直到有一天，數以萬計的追蹤者可以讓自己躋身網路名流，同時藉此 變現。」 關於上文，下列敘述最適當的是：', '["現在的IG主流文化，主要透過商業攝影以賺取流量與金錢", "成為網紅的必要條件之一，是要能忠實記錄自己的日常生活", "IG創設之初鼓勵人以拼貼展示令人羨慕的自己，進而獲得關注", "「以你為核心的世界」，是指創造一個可能脫離現實生活的環境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:25+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00277', 'elementary-acfc4025', 'elementary-acfc4025-moex-113-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「人在誕生前的受精卵狀態，有99%是水；出生後，原本占90%的水在成人之後會降到70%， 據推測死前應該會降至50%吧！換句話說，人終其一生都是活在水的狀態之下。從物質的角 度來看，人就是水。」在文學作品中，也經常可見「水」與「生命」的連結，下列文句中的 「水」，何者最能展現「生命」的意義？', '["天壤之間，水居其多", "水心如鏡面，千里無纖毫", "上善若水，水善利萬物而不爭", "君不見黃河之水天上來，奔流到海不復回"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:25+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00278', 'elementary-acfc4025', 'elementary-acfc4025-moex-113-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「影像的第一印象不只會受到我們當下的狀態影響，連擺頭方向、相機角度等看似不相關的 事情也會造成差異。同一張臉低頭看起來就比較順從，抬頭看起來就比較強勢，頭稍往左傾 會讓臉看起來更可親，更有魅力。我們甚至都還沒開始羅列體態、姿勢、衣服、化妝等各種 情境提示的影響，這一切都影響印象。臉部靜止影像捕捉的是人們在生活的單一片刻，不是 得到精確性格印象的好材料。」 根據上文，下列敘述何者最適當？', '["影像不過是許多不相關事情組成的假象，不可輕信", "透過化妝、衣服、姿勢、角度，可了解真實的性格", "微微低下頭再搭配左傾的臉部，表示此人有好心情", "依賴捕捉片刻的影像來決定第一印象，並不夠準確"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:25+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00279', 'elementary-acfc4025', 'elementary-acfc4025-moex-113-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「江浙一帶是米鄉，嘉興就產好米，嘉興米是溫帶氣候的米，和日本新潟地區的越光米較相 似，日本人在臺灣引進了越光米種出了蓬萊米，就很受來臺的江浙人士喜愛，江浙人是吃不 慣荷蘭人從東南亞引進而種成的在來米的。日本人愛吃黏稠性較高的蓬萊米（越光米種）， 東南亞人吃的是口感較鬆脆的在來米，一般以為蓬萊米較甘甜，口感也更滑順，但在來米炒 飯卻特別好吃。」 根據上文，下列何者最接近文意？', '["「嘉興米」與「在來米」都產於溫帶氣候區，也都是荷蘭人自東南亞所引入臺灣", "新潟地區的「越光米」，產於溫帶氣候，口感較為鬆脆甘甜，較符合日本人口味", "「蓬萊米」原產於江浙一帶，傳至臺灣後由日本人改良，廣泛受到臺灣人的喜愛", "「在來米」是由荷蘭人從東南亞引進，口感鬆脆，比較不符合來臺江浙人的口味"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:25+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00280', 'elementary-acfc4025', 'elementary-acfc4025-moex-113-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「無人存在的空間，就喪失空間的意義；無法傳遞的建築，僅是一座空殼。近千年來，布爾 戈斯主教堂收容了來自世界各地無依的靈魂，迷惘的朝聖者。它具有某種祕而不宣的深刻， 在喧譁塵囂中以無言的方式傳遞信念。」 根據上文，下列何者最接近旅人對布爾戈斯主教堂的讚嘆？', '["顯現華麗精美的設計與建築工法", "展現著修道者刻苦的精神與故事", "傳遞歷史變遷中興盛與衰亡的印記", "長久乘載著人們心靈的苦悶與希望"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:25+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "514", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL)
